css:
.ps-map-drawer { position: absolute; inset-block: 0; inset-inline-end: 0; width: 340px; background: var(--pds-surface-layer); border-inline-start: 1px solid var(--pds-border-subtle); box-shadow: -2px 0 8px rgba(0,0,0,0.12); overflow-y: auto; transform: translateX(100%); transition: transform 250ms cubic-bezier(0.16, 1, 0.3, 1); z-index: 10; }
.ps-map-drawer:not([hidden]) { transform: translateX(0); }
@media (prefers-reduced-motion: reduce) { .ps-map-drawer { transition: opacity 150ms ease; } }
.ps-map-drawer__header { display: flex; align-items: flex-start; justify-content: space-between; padding: var(--pds-space-2); border-block-end: 1px solid var(--pds-border-subtle); }
.ps-map-drawer__title { font-size: 1.0625rem; font-weight: 600; color: var(--pds-text-primary); margin: 0; }
.ps-map-drawer__close { background: transparent; border: none; cursor: pointer; font-size: 1.25rem; color: var(--pds-text-secondary); padding: var(--pds-space-05); }
.ps-map-drawer__facts { display: grid; grid-template-columns: auto 1fr; gap: var(--pds-space-05) var(--pds-space-2); padding: var(--pds-space-2); margin: 0; }
.ps-map-drawer__facts dt { color: var(--pds-text-secondary); font-size: 0.8125rem; }
.ps-map-drawer__facts dd { color: var(--pds-text-primary); font-size: 0.875rem; margin: 0; }
